#!/usr/bin/env node
/**
 * Fixes Table-of-Contents / back-to-top anchor links on the /services/$slug pages.
 *
 * Webstudio generates these same-page anchors as:
 *     href={system?.params?.slug + "#financing"}
 * which react-router resolves RELATIVE to the current route, doubling the slug:
 *     /services/<slug>/<slug>#financing   -> 404
 *
 * They are all same-page fragments, so the slug prefix is wrong. Strip it:
 *     href={"#financing"}
 *
 * Runs post-sync (the generated file is regenerated by `webstudio sync`), so the
 * fix persists across deploys. Idempotent: a second run finds nothing to change.
 */

const fs = require('fs');
const path = require('path');

const GEN_DIR = path.join(__dirname, '..', 'app', '__generated__');
// ponytail: only the services page has these doubled-slug anchors; scan the dir
// anyway so a future page with the same Webstudio pattern gets fixed for free.
const files = fs.readdirSync(GEN_DIR).filter((f) => f.endsWith('.tsx'));

// system?.params?.slug + "#section"  ->  "#section"
const PATTERN = /system\?\.params\?\.slug \+ "#/g;
const REPLACEMENT = '"#';

let total = 0;
let touched = 0;

for (const file of files) {
  const filePath = path.join(GEN_DIR, file);
  const content = fs.readFileSync(filePath, 'utf8');
  const matches = content.match(PATTERN);
  if (!matches) continue;
  fs.writeFileSync(filePath, content.replace(PATTERN, REPLACEMENT));
  console.log(`  ✓ ${file}: fixed ${matches.length} anchor link(s)`);
  total += matches.length;
  touched++;
}

console.log(`\nTOC link fix: ${total} anchor(s) corrected across ${touched} file(s)`);

// self-check: no doubled-slug anchors must remain
for (const file of files) {
  if (PATTERN.test(fs.readFileSync(path.join(GEN_DIR, file), 'utf8'))) {
    console.error(`  ✗ ${file}: doubled-slug anchors still present`);
    process.exit(1);
  }
}
